<script setup lang="ts">
import { updateCheckoutSettings } from '~/services/checkoutService'
import { uploadFile } from '~/utils/supabase'

useHead({ title: 'Checkout Builder' })
useLegacyKiwifyInteractions()
const { complexFieldState } = useComplexFieldMocks()
const { getCheckoutById } = useCheckout()
const route = useRoute()
const checkoutBuilderId = computed(() => String(route.params.id || '176c19f7-fb34-4507-9191-1d277ef99d98'))
const checkoutBuilder = computed(() => getCheckoutById(checkoutBuilderId.value))
const saveCheckout = async () => {
  let logoUrl = complexFieldState.files['checkout-image']
  const logoFile = complexFieldState.fileObjects['checkout-image']
  if (logoFile) {
    const extension = logoFile.name.split('.').pop() || 'png'
    const uploaded = await uploadFile('checkout-assets', `${checkoutBuilderId.value}/asset.${extension}`, logoFile)
    if (uploaded.data?.publicUrl) logoUrl = uploaded.data.publicUrl
  }

  await updateCheckoutSettings(checkoutBuilderId.value, {
    name: document.querySelector<HTMLInputElement>('input.form-input.text-xl')?.value || checkoutBuilder.value?.name,
    logoUrl,
    primaryColor: complexFieldState.colors['checkout-editor'],
    settings: {
      richText: complexFieldState.richText,
      selects: complexFieldState.selects,
      colors: complexFieldState.colors
    }
  })
}
</script>

